// The payload arrives directly as JSON body from FastAPI.
const ctx = $input.first().json.body || $input.first().json;

const anomalySummary = JSON.stringify(ctx.anomaly_type_counts, null, 2);
const severitySummary = JSON.stringify(ctx.severity_counts, null, 2);

const phaseAnalysis = (ctx.process_flow_map || []).map(p =>
  `- ${p.phase}: ${p.total_cases} cases, ${p.anomalies} anomalies (${p.anomaly_rate_pct}% anomaly rate)`
).join('\n');

const topCases = (ctx.top_anomalies || []).slice(0, 10).map((c, i) =>
  `${i+1}. Case ${c.case_id} | ${c.supplier || '-'} | $${(c.amount||0).toLocaleString()} | ${c.anomaly_type} | ${c.severity_label}`
).join('\n');

const prompt = `You are a senior procurement compliance analyst. Analyze the following P2P (Purchase-to-Pay) process mining results and produce a professional structured report.

## Analysis Context
- Report generated for: ${ctx.user_name}
- Analysis run: ${ctx.run_id}
- Source file: ${ctx.file_name || 'uploaded dataset'}
- Generated at: ${ctx.generated_at}

## Executive Summary
- Total cases analyzed: ${ctx.summary?.total_cases || 0}
- Anomalous cases detected: ${ctx.summary?.anomalous_cases || 0}
- Overall anomaly rate: ${ctx.summary?.anomaly_rate_pct || 0}%
- Average processing time: ${ctx.summary?.avg_processing_time_days || 0} days

## Anomaly Severity Breakdown
${severitySummary}

## Anomaly Types Detected
${anomalySummary}

## Process Phase Analysis
${phaseAnalysis}

## Top 10 Critical Cases
${topCases}

---

Produce a structured report with these sections. Be specific, data-driven, and actionable:

1. **EXECUTIVE SUMMARY** (3–4 sentences on overall procurement health)

2. **KEY FINDINGS** (5 most important discoveries as bullet points)

3. **PHASE-BY-PHASE ANALYSIS** (for each process phase: what anomalies exist, business impact)

4. **ANOMALY TYPE DEEP DIVE** (root cause, business risk, financial exposure per anomaly type)

5. **HIGH-RISK CASES** (patterns among the top critical cases)

6. **RECOMMENDATIONS** (5+ specific, prioritised action items with expected impact)

7. **COMPLIANCE RISK ASSESSMENT** (rate: Low / Medium / High / Critical, with justification)

Format in clean Markdown.`;

return [{ json: { ...ctx, groq_prompt: prompt } }];

