// Extract the report markdown from Groq response (OpenAI-compatible format)
const groqResponse = $input.first().json;
const reportMarkdown = groqResponse.choices?.[0]?.message?.content || '';

if (!reportMarkdown) {
  throw new Error('Groq returned an empty response');
}

return [{ json: { report_markdown: reportMarkdown } }];
